import{_ as a,c as i,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Introdução: Expandindo Agentes de IA | Agent Skills","description":"Entenda o Agent Skills e aprenda a expandir agentes de IA como Claude. Apresenta três funcionalidades: otimização React, diretrizes de design e deploy Vercel.","frontmatter":{"title":"Introdução: Expandindo Agentes de IA | Agent Skills","sidebarTitle":"Introdução","subtitle":"Introdução ao Agent Skills","description":"Entenda o Agent Skills e aprenda a expandir agentes de IA como Claude. Apresenta três funcionalidades: otimização React, diretrizes de design e deploy Vercel.","tags":["Introdução","Agente de Codificação por IA","Claude","Pacotes de Habilidades"],"prerequisite":[]},"headers":[],"relativePath":"pt/vercel-labs/agent-skills/start/getting-started/index.md","filePath":"pt/vercel-labs/agent-skills/start/getting-started/index.md"}'),s={name:"pt/vercel-labs/agent-skills/start/getting-started/index.md"};function d(l,e,r,n,c,p){return o(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="introducao-ao-agent-skills" tabindex="-1">Introdução ao Agent Skills <a class="header-anchor" href="#introducao-ao-agent-skills" aria-label="Permalink to &quot;Introdução ao Agent Skills&quot;">​</a></h1><h2 id="o-que-voce-podera-fazer-apos-este-curso" tabindex="-1">O Que Você Poderá Fazer Após Este Curso <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-este-curso" aria-label="Permalink to &quot;O Que Você Poderá Fazer Após Este Curso&quot;">​</a></h2><ul><li>Entender o que é o Agent Skills, e como ele expande a capacidade de agentes de codificação por IA</li><li>Conhecer as três funcionalidades principais dos pacotes de habilidades e seus cenários de uso</li><li>Saber quando é apropriado usar o Agent Skills para melhorar a eficiência de desenvolvimento</li></ul><h2 id="seu-desafio-atual" tabindex="-1">Seu Desafio Atual <a class="header-anchor" href="#seu-desafio-atual" aria-label="Permalink to &quot;Seu Desafio Atual&quot;">​</a></h2><p>Ao usar Claude, Cursor ou outros agentes de codificação por IA no seu dia-a-dia, você pode encontrar estes problemas:</p><ul><li>Quer seguir as melhores práticas, mas não sabe quais regras lembrar</li><li>Frequentemente repete operações de deploy semelhantes, deseja automatizá-las</li><li>O código gerado pela IA tem qualidade inconsistente, faltando padrões unificados</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p><strong>Agent Skills é um sistema de pacotes de habilidades</strong> — fornecendo &quot;plugins&quot; extensíveis para agentes de codificação por IA. Cada habilidade contém:</p><ul><li><strong>SKILL.md</strong>: Arquivo de definição da habilidade, informa ao agente de IA quando ativar essa habilidade</li><li><strong>scripts/</strong>: Scripts auxiliares (como scripts de deploy), executando tarefas específicas</li><li><strong>references/</strong>: Documentação auxiliar (opcional), fornecendo materiais de referência detalhados</li></ul><div class="tip custom-block"><p class="custom-block-title">Filosofia de Design</p><p>As habilidades usam um <strong>mecanismo de carregamento sob demanda</strong>: apenas o nome e a descrição das habilidades são carregados ao iniciar; o conteúdo completo é lido apenas quando a IA considera necessário. Isso reduz o uso do contexto e melhora a eficiência.</p></div><h2 id="pacotes-de-habilidades-disponiveis" tabindex="-1">Pacotes de Habilidades Disponíveis <a class="header-anchor" href="#pacotes-de-habilidades-disponiveis" aria-label="Permalink to &quot;Pacotes de Habilidades Disponíveis&quot;">​</a></h2><p>O projeto fornece três pacotes de habilidades principais, cada direcionado para um cenário específico:</p><h3 id="react-best-practices" tabindex="-1">react-best-practices <a class="header-anchor" href="#react-best-practices" aria-label="Permalink to &quot;react-best-practices&quot;">​</a></h3><p>Guia de otimização de desempenho do React e Next.js, dos padrões de Engenharia da Vercel. Inclui mais de 50 regras, classificadas por nível de impacto.</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Escrevendo novos componentes React ou páginas Next.js</li><li>Auditando problemas de desempenho de código</li><li>Otimizando tamanho de empacotamento ou tempo de carregamento</li></ul><p><strong>Categorias Cobertas</strong>:</p><ul><li>Eliminando Cachoeiras (Critical)</li><li>Otimização de Tamanho de Empacotamento (Critical)</li><li>Desempenho no Servidor (High)</li><li>Busca de Dados no Cliente (Medium-High)</li><li>Otimização de Re-render (Medium)</li><li>Desempenho de Renderização (Medium)</li><li>Micro-otimizações JavaScript (Low-Medium)</li><li>Modos Avançados (Low)</li></ul><h3 id="web-design-guidelines" tabindex="-1">web-design-guidelines <a class="header-anchor" href="#web-design-guidelines" aria-label="Permalink to &quot;web-design-guidelines&quot;">​</a></h3><p>Auditoria de diretrizes de design de interface web, verificando se o código atende quase 100 melhores práticas.</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Prompt: &quot;Review my UI&quot;</li><li>Verificando acessibilidade (Accessibility)</li><li>Auditando consistência de design</li><li>Verificando desempenho e UX</li></ul><p><strong>Categorias Cobertas</strong>:</p><ul><li>Acessibilidade (aria-labels, HTML semântico, tratamento de teclado)</li><li>Estados de Foco (foco visível, modo focus-visible)</li><li>Formulários (autocompletar, validação, tratamento de erros)</li><li>Animação (prefers-reduced-motion, transformações amigáveis à composição)</li><li>Imagens (dimensões, lazy loading, texto alt)</li><li>Tipografia, desempenho, navegação, etc.</li></ul><h3 id="vercel-deploy-claimable" tabindex="-1">vercel-deploy-claimable <a class="header-anchor" href="#vercel-deploy-claimable" aria-label="Permalink to &quot;vercel-deploy-claimable&quot;">​</a></h3><p>Deploy com um clique de aplicativos e sites no Vercel, retornando links de preview e de transferência de propriedade.</p><p><strong>Cenários de Uso</strong>:</p><ul><li>Prompt: &quot;Deploy my app&quot;</li><li>Compartilhar rapidamente o preview do projeto</li><li>Deploy sem configuração, sem autenticação</li></ul><p><strong>Funcionalidades Principais</strong>:</p><ul><li>Detecta automaticamente mais de 40 frameworks (Next.js, Vite, Astro, etc.)</li><li>Retorna URL de preview (site ao vivo) e URL de claim (transferência de propriedade)</li><li>Trata automaticamente projetos HTML estáticos</li><li>Exclui <code>node_modules</code> e <code>.git</code> durante o upload</li></ul><h2 id="como-as-habilidades-funcionam" tabindex="-1">Como as Habilidades Funcionam <a class="header-anchor" href="#como-as-habilidades-funcionam" aria-label="Permalink to &quot;Como as Habilidades Funcionam&quot;">​</a></h2><p>Quando você usa Claude ou outro agente de IA, o fluxo de ativação de habilidades é o seguinte:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Usuário entra com tarefa] --&gt; B[IA detecta palavras-chave&lt;br/&gt;como Deploy, Review, Optimize]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[Combina descrição da habilidade]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Carrega conteúdo completo SKILL.md]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[Executa script ou aplica regras]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Envia resultado ao usuário]</span></span></code></pre></div><p><strong>Exemplo de Fluxo</strong>:</p><ol><li><strong>Entrada do Usuário</strong>: &quot;Deploy my app&quot;</li><li><strong>Detecção da IA</strong>: Identifica a palavra-chave &quot;Deploy&quot;, combina com habilidade <code>vercel-deploy</code></li><li><strong>Carregamento da Habilidade</strong>: Lê o conteúdo completo do <code>SKILL.md</code></li><li><strong>Execução do Deploy</strong>: <ul><li>Executa script <code>deploy.sh</code></li><li>Detecta framework (lê package.json)</li><li>Empacota projeto em tarball</li><li>Faz upload para API Vercel</li></ul></li><li><strong>Retorno de Resultado</strong>:<div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;previewUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://skill-deploy-abc123.vercel.app&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;claimUrl&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://vercel.com/claim-deployment?code=...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><h2 id="quando-usar-esta-abordagem" tabindex="-1">Quando Usar Esta Abordagem <a class="header-anchor" href="#quando-usar-esta-abordagem" aria-label="Permalink to &quot;Quando Usar Esta Abordagem&quot;">​</a></h2><p>Melhores momentos para usar o Agent Skills:</p><table tabindex="0"><thead><tr><th>Cenário</th><th>Habilidade Usada</th><th>Exemplo de Prompt de Acionamento</th></tr></thead><tbody><tr><td>Escrevendo componentes React</td><td>react-best-practices</td><td>&quot;Review this React component for performance issues&quot;</td></tr><tr><td>Otimizando páginas Next.js</td><td>react-best-practices</td><td>&quot;Help me optimize this Next.js page&quot;</td></tr><tr><td>Verificando qualidade da UI</td><td>web-design-guidelines</td><td>&quot;Check accessibility of my site&quot;</td></tr><tr><td>Fazendo deploy de projetos</td><td>vercel-deploy-claimable</td><td>&quot;Deploy my app to production&quot;</td></tr></tbody></table><h2 id="modelo-de-seguranca" tabindex="-1">Modelo de Segurança <a class="header-anchor" href="#modelo-de-seguranca" aria-label="Permalink to &quot;Modelo de Segurança&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Notas de Segurança</p><ul><li><strong>Execução local</strong>: Todas as habilidades são executadas localmente, sem upload de dados a serviços terceiros (exceto API de deploy Vercel)</li><li><strong>Ativação sob demanda</strong>: As habilidades carregam conteúdo detalhado apenas quando a IA considera relevante, reduzindo risco de vazamento de privacidade</li><li><strong>Código aberto e transparente</strong>: Todas as habilidades e scripts são open source e auditáveis</li></ul></div><h2 id="armadilhas" tabindex="-1">Armadilhas <a class="header-anchor" href="#armadilhas" aria-label="Permalink to &quot;Armadilhas&quot;">​</a></h2><h3 id="habilidade-nao-ativada" tabindex="-1">Habilidade Não Ativada <a class="header-anchor" href="#habilidade-nao-ativada" aria-label="Permalink to &quot;Habilidade Não Ativada&quot;">​</a></h3><p>Se a habilidade não foi ativada, verifique:</p><ul><li>O prompt contém palavras-chave suficientes (como &quot;Deploy&quot;, &quot;Review&quot;)</li><li>A habilidade foi corretamente instalada no diretório <code>~/.claude/skills/</code></li><li>Se estiver usando claude.ai, confirme se a habilidade foi adicionada ao knowledge do projeto</li></ul><h3 id="permissoes-de-rede" tabindex="-1">Permissões de Rede <a class="header-anchor" href="#permissoes-de-rede" aria-label="Permalink to &quot;Permissões de Rede&quot;">​</a></h3><p>Algumas habilidades precisam de acesso à rede:</p><ul><li><code>vercel-deploy-claimable</code> precisa acessar API de deploy Vercel</li><li><code>web-design-guidelines</code> precisa buscar as regras mais recentes do GitHub</li></ul><p><strong>Solução</strong>: Adicione os domínios necessários em claude.ai/settings/capabilities.</p><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Agent Skills é um sistema de pacotes de habilidades projetado para agentes de codificação por IA, fornecendo:</p><ul><li><strong>react-best-practices</strong>: Mais de 50 regras de otimização de desempenho do React/Next.js</li><li><strong>web-design-guidelines</strong>: Quase 100 melhores práticas de design web</li><li><strong>vercel-deploy-claimable</strong>: Deploy com um clique no Vercel</li></ul><p>As habilidades usam um mecanismo de carregamento sob demanda para reduzir o uso do contexto. Após a instalação, os agentes de IA ativarão automaticamente as habilidades correspondentes em tarefas relevantes.</p><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../installation/">Instalando o Agent Skills</a></strong>.</p><p>Você aprenderá:</p><ul><li>Dois métodos de instalação: Claude Code e claude.ai</li><li>Configurando permissões de rede</li><li>Verificando se as habilidades foram corretamente instaladas</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir localizações do código fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Número de Linha</th></tr></thead><tbody><tr><td>Lista de pacotes de habilidades</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L7-L80" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>7-80</td></tr><tr><td>Descrição de estrutura de habilidades</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/README.md#L103-L110" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>103-110</td></tr><tr><td>Especificação AGENTS.md</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>Total</td></tr><tr><td>Estrutura de diretório de habilidades</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>11-20</td></tr><tr><td>Formato SKILL.md</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>29-68</td></tr><tr><td>Comando de empacotamento de habilidades</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L93-L96" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>93-96</td></tr><tr><td>Método de instalação do usuário</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L98-L110" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>98-110</td></tr><tr><td>Mecanismo de carregamento sob demanda</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L72-L78" target="_blank" rel="noreferrer"><code>AGENTS.md</code></a></td><td>72-78</td></tr><tr><td>Scripts de cadeia de ferramentas de build</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>Total</td></tr></tbody></table><p><strong>Constantes Chave</strong>:</p><ul><li>Sem constantes embutidas em código</li></ul><p><strong>Funções Chave</strong>:</p><ul><li><code>build.ts</code>: Constrói AGENTS.md e casos de teste</li><li><code>validate.ts</code>: Valida integridade de arquivos de regras</li><li><code>extract-tests.ts</code>: Extrai casos de teste de regras</li></ul></details>`,57)])])}const h=a(s,[["render",d]]);export{m as __pageData,h as default};
